import pickle
import json
import os
from typing import Any, Dict, List, Union
from pathlib import Path

def save_preferences(preferences: Dict[str, Any], filepath: str, secure: bool = True) -> None:
    """
    Save user preferences to a file using pickle for complex objects.
    """
    try:
        if secure:
            # Ensure secure file permissions
            Path(filepath).parent.mkdir(parents=True, exist_ok=True)
            os.chmod(filepath, 0o600)
        
        with open(filepath, 'wb') as f:
            pickle.dump(preferences, f, protocol=pickle.HIGHEST_PROTOCOL)
    except Exception as e:
        raise IOError(f"Failed to save preferences: {str(e)}")

def load_preferences(filepath: str, secure: bool = True) -> Dict[str, Any]:
    """
    Load user preferences from a file.
    """
    try:
        if not os.path.exists(filepath):
            return {}
        
        if secure:
            # Verify file permissions
            stat = os.stat(filepath)
            if stat.st_mode & 0o077:
                raise PermissionError("Insecure file permissions detected")
        
        with open(filepath, 'rb') as f:
            preferences = pickle.load(f)
            return preferences if isinstance(preferences, dict) else {}
    except (pickle.UnpicklingError, EOFError, PermissionError) as e:
        raise ValueError(f"Failed to load preferences: {str(e)}")
    except Exception as e:
        raise IOError(f"Unexpected error loading preferences: {str(e)}")

def save_preferences_json(preferences: Dict[str, Any], filepath: str) -> None:
    """
    Save user preferences to a JSON file for compatibility.
    """
    try:
        Path(filepath).parent.mkdir(parents=True, exist_ok=True)
        with open(filepath, 'w') as f:
            json.dump(preferences, f, indent=2, default=str)
    except Exception as e:
        raise IOError(f"Failed to save preferences: {str(e)}")

def load_preferences_json(filepath: str) -> Dict[str, Any]:
    """
    Load user preferences from a JSON file.
    """
    try:
        if not os.path.exists(filepath):
            return {}
        
        with open(filepath, 'r') as f:
            return json.load(f)
    except (json.JSONDecodeError, IOError) as e:
        raise ValueError(f"Failed to load preferences: {str(e)}")